     1→const express = require('express');
     2→const pool = require('../lib/db');
     3→const { authMiddleware, optionalAuth, requireRole } = require('../lib/auth');
     4→
     5→const router = express.Router();
     6→
     7→// List jobs (public) with search/filter
     8→router.get('/', optionalAuth, async (req, res) => {
     9→  try {
    10→    const { status = 'active', limit = 20, offset = 0, search, location, job_type, salary_min, salary_max } = req.query;
    11→
    12→    let query = `
    13→      SELECT j.*, u.company_name as poster_company
    14→      FROM jobs j
    15→      LEFT JOIN users u ON j.user_id = u.id
    16→      WHERE j.status = $1
    17→    `;
    18→    const params = [status];
    19→    let idx = 2;
    20→
    21→    // Text search across title, company, description, requirements
    22→    if (search && search.trim()) {
    23→      query += ` AND (
    24→        j.title ILIKE $${idx} OR j.company ILIKE $${idx}
    25→        OR j.description ILIKE $${idx} OR j.requirements ILIKE $${idx}
    26→      )`;
    27→      params.push(`%${search.trim()}%`);
    28→      idx++;
    29→    }
    30→
    31→    // Location filter (partial match)
    32→    if (location && location.trim()) {
    33→      query += ` AND j.location ILIKE $${idx}`;
    34→      params.push(`%${location.trim()}%`);
    35→      idx++;
    36→    }
    37→
    38→    // Job type filter (exact match)
    39→    if (job_type && job_type.trim()) {
    40→      query += ` AND j.job_type = $${idx}`;
    41→      params.push(job_type.trim());
    42→      idx++;
    43→    }
    44→
    45→    // Salary range filters
    46→    if (salary_min) {
    47→      query += ` AND (j.salary_min >= $${idx} OR j.salary_min IS NULL)`;
    48→      params.push(parseInt(salary_min));
    49→      idx++;
    50→    }
    51→    if (salary_max) {
    52→      query += ` AND (j.salary_max <= $${idx} OR j.salary_max IS NULL)`;
    53→      params.push(parseInt(salary_max));
    54→      idx++;
    55→    }
    56→
    57→    query += ` ORDER BY j.created_at DESC LIMIT $${idx} OFFSET $${idx + 1}`;
